mapper.select:
SELECT t.id, t.instance_id, t.node_id, t.node_log_id, t.task_type, t.assignee_type, t.assignee_ids, t.assignee_expression, t.title, t.description, t.content, t.status, t.action, t.result, t.comment, t.timeout_minutes, t.timeout_action, t.delegated_to, t.delegated_at, t.due_at, t.started_at, t.completed_at, t.created_at, d.name AS workflow_name, i.workflow_id FROM human_task t LEFT JOIN workflow_instance i ON t.instance_id = i.id LEFT JOIN workflow_definition d ON i.workflow_id = d.id
AND t.task_type = #{taskType}
AND t.status = #{status}
AND t.instance_id = #{instanceId}
AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.created_at DESC

mapper.update:
UPDATE human_task
action = #{action}, result = #{result}, comment = #{comment}, status = #{status}, started_at = #{startedAt}, completed_at = #{completedAt}, delegated_to = #{delegatedTo}, delegated_at = #{delegatedAt},
WHERE id = #{id}
